// SR Format v2 — hybrid search + tiered snippets + token budget
const items = $input.all();
const body = $('Zikra Webhook').first().json.body;

// Token budget: caller can pass max_tokens, default 1500
const TOKEN_BUDGET = body.max_tokens || 1500;
// Rough chars-per-token estimate for English text
const CHARS_PER_TOKEN = 4;
const CHAR_BUDGET = TOKEN_BUDGET * CHARS_PER_TOKEN;

// Tiered snippet lengths by rank position
const SNIPPET_LENGTHS = [500, 300, 200, 150, 150];

let results = [];
let totalChars = 0;

for (let i = 0; i < items.length; i++) {
    const item = items[i];
    if (item.json.error) continue;

    // Tiered truncation — top result gets most context
    const maxLen = SNIPPET_LENGTHS[i] || 150;
    const fullSnippet = item.json.snippet || item.json.content_snippet || '';
    const snippet = fullSnippet.substring(0, maxLen);

    // Enforce token budget — stop adding results once exceeded
    const entryChars = (item.json.title || '').length + snippet.length;
    if (totalChars + entryChars > CHAR_BUDGET && results.length > 0) break;
    totalChars += entryChars;

    results.push({
        id: item.json.id,
        title: item.json.title,
        snippet: snippet,
        memory_type: item.json.memory_type,
        project: item.json.project,
        module: item.json.module,
        _raw_score: item.json.score,
        score: item.json.score,
        created_at: item.json.created_at,
        access_count: item.json.access_count,
        confidence_score: item.json.confidence_score
    });
}

return [{
    json: {
        results,
        count: results.length,
        mode: 'hybrid',
        token_budget_used: Math.round(totalChars / CHARS_PER_TOKEN)
    }
}];

