FROM zikra.memories
WHERE memory_type = 'schema'
  AND project = '{{ $("Zikra Webhook").first().json.body.project }}'
  {{ $("Zikra Webhook").first().json.body.module ? "AND module = '"+$("Zikra Webhook").first().json.body.module+"'" : "" }}
