const row = $input.first().json;
const wb  = $('Zikra Webhook').first().json.body;
const project = wb.project || 'unknown';
const mod     = wb.module  || 'core';
const errors    = row.errors    || [];
const prompts   = row.prompts   || [];
const decisions = row.decisions || [];
const schema    = row.schema_content || '';

const errSec = errors.length
  ? errors.map(e=>`### ${e.title}\n${e.snippet}\n_${e.created_at}_`).join('\n\n')
  : '_No unresolved errors_';
const decSec = decisions.length
  ? decisions.map(d=>`### ${d.title}\n${d.snippet}`).join('\n\n')
  : '_No recent decisions_';
const prmSec = prompts.length
  ? prompts.map(p=>`- **${p.title}**: ${p.snippet}`).join('\n')
  : '_None_';

const claudemd = `# Project: ${project}
# Cortex: https://n8n.veltisai.com/webhook/cortex
# Module: ${mod}

## Recent Unresolved Errors
${errSec}

## Current Schema (${mod})
${schema || '_No schema found_'}

## Active Decisions
${decSec}

## Top Prompts
${prmSec}

## Debug Protocol
1. Read exact error — do not paraphrase
2. Search cortex: cortex search <error>
3. Check known resolutions
4. Fix or escalate
5. Log to cortex: cortex log_error
`;
return [{json:{claudemd,project,module:mod}}];

