WITH upd AS (
    UPDATE zikra.memories
    SET access_count = access_count + 1
    WHERE (
        id = '{{ ($("Zikra Webhook").first().json.body.id||"00000000-0000-0000-0000-000000000000").replace(/'/g,"''") }}'::uuid
        OR LOWER(title) = LOWER('{{ ($("Zikra Webhook").first().json.body.title||"").replace(/'/g,"''") }}')
    )
    RETURNING id, title, content_md, memory_type, project, module, created_at, access_count, tags
)
SELECT * FROM upd LIMIT 1;

