const ALIASES = {
  // search aliases
  find:           'search',
  query:          'search',
  recall:         'search',
  lookup:         'search',
  search_memory:  'search',
  find_memory:    'search',
  retrieve:       'search',
  remember:       'search',

  // save_memory aliases
  save:           'save_memory',
  store:          'save_memory',
  write_memory:   'save_memory',
  add_memory:     'save_memory',
  write:          'save_memory',

  // get_prompt aliases
  run_prompt:     'get_prompt',
  fetch_prompt:   'get_prompt',
  load_prompt:    'get_prompt',
  execute_prompt: 'get_prompt',
  get_prompt:     'get_prompt',

  // get_memory aliases
  fetch_memory:   'get_memory',
  read_memory:    'get_memory',
  load_memory:    'get_memory',

  // log_run aliases
  log_session:    'log_run',
  end_session:    'log_run',
  finish_run:     'log_run',
  log_completion: 'log_run',

  // log_error aliases
  log_bug:        'log_error',
  report_error:   'log_error',
  save_error:     'log_error',
  log_failure:    'log_error',

  // sync_claudemd aliases
  sync:           'sync_claudemd',
  claudemd:       'sync_claudemd',

  // debug_protocol aliases
  debug:          'debug_protocol',
  dp:             'debug_protocol',

  // get_schema aliases
  schema:         'get_schema',
  get_db:         'get_schema',
};

const item = $input.first();
const body = item.json.body || {};
const raw = (body.command || '').toLowerCase().trim();
const canonical = ALIASES[raw] || raw;

// Mutate body.command to canonical form
body.command = canonical;

// Attach metadata for downstream response hints
body._raw_command = raw;
body._canonical_command = canonical;
body._was_alias = (raw !== canonical);

return [item];

const now = Date.now();
const LN2 = 0.693;

function scoreItem(rawScore, item) {
  const created = item.created_at ? new Date(item.created_at).getTime() : now;
  const ageDays = Math.max(0, (now - created) / (1000 * 60 * 60 * 24));
  const decay = Math.max(0.05, Math.exp(-LN2 * ageDays / 30));
  const freq  = 1.0 + 0.1 * Math.log1p(item.access_count || 0);
  const conf  = parseFloat(item.confidence_score || 1.0);
  return rawScore * decay * freq * conf;
}

const input = .first().json;
const results = (input.results || []).map(item => {
  const raw = item._raw_score || item.score || 1.0;
  return {
    ...item,
    final_score: scoreItem(raw, item)
  };
}).sort((a, b) => b.final_score - a.final_score);

// Strip scoring internals before response
const clean = results.map(({ _raw_score, access_count, confidence_score, final_score, ...rest }) => ({
  ...rest,
  score: parseFloat(final_score.toFixed(4))
}));

return [{
  json: {
    results: clean,
    count: clean.length,
    mode: input.mode,
    token_budget_used: input.token_budget_used
  }
}];
